import{_ as t,c as s,o as e,a5 as a}from"./chunks/framework.CgT1UzWm.js";const k=JSON.parse('{"title":"Changelog v3.4.7 (2025-01-21)","description":"NpgsqlRest v3.4.7: Release notes: Type Category Lookup Optimization; Additional Allocation Optimizations","frontmatter":{"description":"NpgsqlRest v3.4.7: Release notes: Type Category Lookup Optimization; Additional Allocation Optimizations","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.4.7.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.4.7.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.4.7 (2025-01-21)"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.4.7: Release notes: Type Category Lookup Optimization; Additional Allocation Optimizations"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.4.7 (2025-01-21)"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.4.7: Release notes: Type Category Lookup Optimization; Additional Allocation Optimizations"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.4.7.md","filePath":"guide/changelog/v3.4.7.md","lastUpdated":1782480183000}'),n={name:"guide/changelog/v3.4.7.md"};function o(l,i,p,r,h,d){return e(),s("div",null,i[0]||(i[0]=[a(`<h1 id="changelog-v3-4-7-2025-01-21" tabindex="-1">Changelog v3.4.7 (2025-01-21) <a class="header-anchor" href="#changelog-v3-4-7-2025-01-21" aria-label="Permalink to &quot;Changelog v3.4.7 (2025-01-21)&quot;">​</a></h1><h2 id="version-3-4-7-2025-01-21" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.7" target="_blank" rel="noreferrer">3.4.7</a> (2025-01-21) <a class="header-anchor" href="#version-3-4-7-2025-01-21" aria-label="Permalink to &quot;Version [3.4.7](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.7) (2025-01-21)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.4.6...3.4.7" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="type-category-lookup-optimization" tabindex="-1">Type Category Lookup Optimization <a class="header-anchor" href="#type-category-lookup-optimization" aria-label="Permalink to &quot;Type Category Lookup Optimization&quot;">​</a></h3><p>Introduced <code>TypeCategory</code> flags enum and pre-computed lookup table for O(1) type dispatch, replacing sequential if-chain conditionals in hot paths.</p><p><strong>New Files:</strong></p><ul><li><code>TypeCategory.cs</code> - Flags enum (<code>Numeric</code>, <code>Boolean</code>, <code>Json</code>, <code>Text</code>, <code>DateTime</code>, <code>Date</code>, <code>NeedsEscape</code>, <code>CastToText</code>, <code>Binary</code>, <code>Time</code>) and <code>TypeCategoryLookup</code> static class with 128-element array for instant type classification</li><li><code>ParameterParsers.cs</code> - Delegate array for O(1) parameter parser lookup by <code>NpgsqlDbType</code></li></ul><p><strong>Changes:</strong></p><ul><li><code>TypeDescriptor</code> now has a <code>Category</code> property computed once at construction via lookup table</li><li>Boolean properties (<code>IsNumeric</code>, <code>IsJson</code>, <code>IsText</code>, etc.) are now computed from <code>Category</code> using bitwise operations</li><li><code>NpgsqlRestEndpoint.cs</code> and <code>PgConverters.cs</code> use bitwise category checks for type dispatch</li></ul><p><strong>Benchmark Results:</strong></p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Operation</th><th>Before</th><th>After</th><th>Improvement</th></tr></thead><tbody><tr><td>Type category lookup (18 types)</td><td>22.6 ns</td><td>6.6 ns</td><td><strong>70% faster</strong></td></tr><tr><td>TypeDescriptor construction</td><td>232.8 ns</td><td>164.2 ns</td><td><strong>29% faster</strong></td></tr><tr><td>Parser delegate lookup</td><td>7.6 ns</td><td>5.9 ns</td><td><strong>23% faster</strong></td></tr><tr><td>Combined type check (bitwise vs properties)</td><td>7.97 ns</td><td>4.94 ns</td><td><strong>38% faster</strong></td></tr><tr><td>Serialization type check (1000 rows)</td><td>5,572 ns</td><td>4,060 ns</td><td><strong>27% faster</strong></td></tr></tbody></table></div></div><p><strong>Note:</strong> While micro-benchmarks show significant improvements, real-world endpoint throughput gains are modest (1-5%) since type dispatch is a small fraction of total request time compared to database I/O and serialization.</p><h3 id="additional-allocation-optimizations" tabindex="-1">Additional Allocation Optimizations <a class="header-anchor" href="#additional-allocation-optimizations" aria-label="Permalink to &quot;Additional Allocation Optimizations&quot;">​</a></h3><p><strong>Parameter Logging String Allocations</strong></p><p>Replaced <code>string.Concat()</code> with <code>paramIndex.ToString()</code> in 8 logging paths with direct <code>StringBuilder.Append(int)</code> calls, eliminating intermediate string allocations for each logged parameter.</p><p>Before:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">cmdLog</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">!.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">AppendLine</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">string</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">Concat</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;-- $&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> paramIndex</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">ToString</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(),</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot; &quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> ..</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">.</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>After:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">cmdLog</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">!.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">Append</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;-- $&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">Append</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">paramIndex</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">Append</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">Append</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">..</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">.</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">AppendLine</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">p</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p><strong>Cache Key String Reuse</strong></p><p>Cache key string (<code>cacheKeys.ToString()</code>) was being called 3-6 times per cached request. Now computed once and reused:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">string</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">?</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> cacheKeyString </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> cacheKeys</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">?.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">ToString</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">();</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">// Reused in all cache Get/AddOrUpdate calls</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p><strong>Impact:</strong> Eliminates 8+ string allocations per parameter-heavy request (logging) and 2-5 allocations per cached request (cache keys).</p><hr>`,24)]))}const g=t(n,[["render",o]]);export{k as __pageData,g as default};
